INSERT OR REPLACE INTO verses (id,work_id,division_id,ref,ordinal,devanagari,translit,uvaca,source_url) VALUES ('cb.adi.9.62','cb','cb.adi.9','ЧБ Ади 9.62',62,'শুনি’ পিতা-মাতা ধাই’ আইল সত্বরে ।
দেখয়ে,—পুত্ত্রের ধাতু নাহিক শরীরে ॥৬২॥','ш́уни’ пита̄-ма̄та̄ дха̄и’ а̄ила сатваре
декхайе, — путрера дха̄ту на̄хика ш́арӣре',NULL,NULL),('cb.adi.9.63','cb','cb.adi.9','ЧБ Ади 9.63',63,'মূর্চ্ছিত হইয়া দোঁহে পড়িলা ভূমিতে ।
দেখি’ সর্ব্বলোক আসি’ হইলা বিস্মিতে ॥৬৩॥','мӯрчхита хаийа̄ дон̇хе пад̣ила̄ бхӯмите
декхи’ сарва-лока а̄си’ хаила̄ висмите',NULL,NULL),('cb.adi.9.64','cb','cb.adi.9','ЧБ Ади 9.64',64,'সকল বৃত্তান্ত তবে কহিল শিশুগণ ।
কেহ বোলে,—“বুঝিলাঙ ভাবের কারণ ॥৬৪॥','сакала вр̣тта̄нта табе кахила ш́иш́у-ган̣а
кеха боле, — ’буджхила̄н̇а бха̄вера ка̄ран̣а',NULL,NULL),('cb.adi.9.65','cb','cb.adi.9','ЧБ Ади 9.65',65,'পূর্ব্বে দশরথ-ভাবে এক নটবর ।
‘রাম—বনবাসী’ শুনি’ এড়েন কলেবর” ॥৬৫॥','пӯрве даш́аратха-бха̄ве эка нат̣авара
‘ра̄ма — ванава̄сӣ’ ш́уни’ эд̣ена калевара’',NULL,NULL),('cb.adi.9.66','cb','cb.adi.9','ЧБ Ади 9.66',66,'কেহ বোলে,—“কাচ কাচি’ আছয়ে ছাওয়াল ।
হনূমান্ ঔষধ দিলে হইবেক ভাল” ॥৬৬॥','кеха боле — ’ка̄ча ка̄чи’ а̄чхайе чха̄ойа̄ла
ханума̄н ауш̣адха диле хаибека бха̄ла',NULL,NULL),('cb.adi.9.67','cb','cb.adi.9','ЧБ Ади 9.67',67,'পূর্ব্বে প্রভু শিখাইয়াছিলেন সবারে ।
“পড়িলে, তোমরা বেড়ি’ কান্দিহ আমারে ॥৬৭॥','пӯрве прабху ш́икха̄ийа̄чхилена саба̄ре
‘пад̣иле, томара̄ вед̣и’ ка̄ндиха а̄ма̄ре',NULL,NULL),('cb.adi.9.68','cb','cb.adi.9','ЧБ Ади 9.68',68,'ক্ষণেক বিলম্বে পাঠাইহ হনূমান্ ।
নাকে দিলে ঔষধ, আসিবে মোর প্রাণ” ॥৬৮॥','кш̣анека виламбе па̄т̣ха̄иха ханума̄н
на̄ке диле ауш̣адха, а̄сибе мора пра̄н̣а’',NULL,NULL),('cb.adi.9.69','cb','cb.adi.9','ЧБ Ади 9.69',69,'নিজভাবে প্রভু মাত্র হৈলা অচেতন ।
দেখি’ বড় বিকল হৈলা শিশুগণ ॥৬৯॥','ниджа-бха̄ве прабху ма̄тра хаила̄ ачетана
декхи’ бад̣а викала хаила̄ ш́иш́у-ган̣а',NULL,NULL),('cb.adi.9.70','cb','cb.adi.9','ЧБ Ади 9.70',70,'ছন্ন হইলেন সবে, শিক্ষা নাহি স্ফুরে ।
“উঠ, ভাই” বলি’ মাত্র কান্দে উচ্চৈঃস্বরে ॥৭০॥','чханна хаилена сабе, ш́икш̣а̄ на̄хи спхуре
‘ут̣ха бха̄и’ бали’ ма̄тра ка̄нде уччаих̣-сваре',NULL,NULL),('cb.adi.9.71','cb','cb.adi.9','ЧБ Ади 9.71',71,'লোকমুখে শুনি’ কথা হইল স্মরণ ।
হনূমান্-কাচে শিশু চলিল তখন ॥৭১॥','лока-мукхе ш́ӯни’ катха̄ хаила смаран̣а
ханума̄н-ка̄че ш́иш́у чалила такхана',NULL,NULL),('cb.adi.9.72','cb','cb.adi.9','ЧБ Ади 9.72',72,'আর এক শিশু পথে তপস্বীর বেশে ।
ফল-মূল দিয়া হনূমানেরে আশংসে ॥৭২॥','а̄ра эка ш́иш́у патхе тапасвӣра веш́е
